		ВызватьИсключение "Не указан склад для списания товаров";
	КонецЕсли;

	// Получаем список номенклатуры для запроса
	СписокНоменклатуры = Новый Массив;
	Для Каждого СтрокаТовара Из ТоварыКСписанию Цикл
		Если ЗначениеЗаполнено(СтрокаТовара.Номенклатура) Тогда
			СписокНоменклатуры.Добавить(СтрокаТовара.Номенклатура);
		КонецЕсли;
	КонецЦикла;

	Если СписокНоменклатуры.Количество() = 0 Тогда
		Возврат РезультатРаспределения;
	КонецЕсли;

	// Запрос остатков с партионным учетом (FIFO по дате поступления через серии)
	Запрос = Новый Запрос;
	Запрос.Текст = 
	"ВЫБРАТЬ
	|	ТоварыКСписанию.Номенклатура КАК Номенклатура,
	|	ТоварыКСписанию.Количество КАК КоличествоТребуется
	|ПОМЕСТИТЬ ТоварыКСписанию
	|ИЗ
	|	&ТоварыКСписанию КАК ТоварыКСписанию
	|;
	|
	|////////////////////////////////////////////////////////////////////////////////
	|ВЫБРАТЬ
	|	ТоварыНаСкладахОстатки.Номенклатура КАК Номенклатура,
	|	ТоварыНаСкладахОстатки.Характеристика КАК Характеристика,
	|	ТоварыНаСкладахОстатки.Серия КАК Серия,
	|	ТоварыНаСкладахОстатки.ВНаличииОстаток КАК ВНаличии
	|ПОМЕСТИТЬ ОстаткиПоПартиям
	|ИЗ
	|	РегистрНакопления.ТоварыНаСкладах.Остатки(
	|			,
	|			Склад = &Склад
	|				И Номенклатура В (&СписокНоменклатуры)) КАК ТоварыНаСкладахОстатки
	|ГДЕ
	|	ТоварыНаСкладахОстатки.ВНаличииОстаток > 0
	|;
	|
	|////////////////////////////////////////////////////////////////////////////////
	|ВЫБРАТЬ
	|	ТоварыКСписанию.Номенклатура КАК Номенклатура,
	|	ТоварыКСписанию.КоличествоТребуется КАК КоличествоТребуется,
	|	ЕСТЬNULL(ОстаткиИтого.ВсегоВНаличии, 0) КАК ВсегоВНаличии
	|ПОМЕСТИТЬ ПроверкаОстатков
	|ИЗ
	|	ТоварыКСписанию КАК ТоварыКСписанию
	|		ЛЕВОЕ СОЕДИНЕНИЕ (ВЫБРАТЬ
	|			ОстаткиПоПартиям.Номенклатура КАК Номенклатура,
	|			СУММА(ОстаткиПоПартиям.ВНаличии) КАК ВсегоВНаличии
	|		ИЗ
	|			ОстаткиПоПартиям КАК ОстаткиПоПартиям
	|		
	|		СГРУППИРОВАТЬ ПО
	|			ОстаткиПоПартиям.Номенклатура) КАК ОстаткиИтого
	|		ПО ТоварыКСписанию.Номенклатура = ОстаткиИтого.Номенклатура
	|;
	|
	|////////////////////////////////////////////////////////////////////////////////
	|ВЫБРАТЬ
	|	ПроверкаОстатков.Номенклатура КАК Номенклатура,
	|	ПроверкаОстатков.Номенклатура.Наименование КАК Наименование,
	|	ПроверкаОстатков.КоличествоТребуется КАК КоличествоТребуется,
	|	ПроверкаОстатков.ВсегоВНаличии КАК ВсегоВНаличии
	|ИЗ
	|	ПроверкаОстатков КАК ПроверкаОстатков
	|ГДЕ
	|	ПроверкаОстатков.КоличествоТребуется > ПроверкаОстатков.ВсегоВНаличии
	|;
	|
	|////////////////////////////////////////////////////////////////////////////////
	|ВЫБРАТЬ
	|	ОстаткиПоПартиям.Номенклатура КАК Номенклатура,
	|	ОстаткиПоПартиям.Характеристика КАК Характеристика,
	|	ОстаткиПоПартиям.Серия КАК Серия,
	|	ОстаткиПоПартиям.ВНаличии КАК ВНаличии,
	|	ЕСТЬNULL(ОстаткиПоПартиям.Серия.ДатаПроизводства, ДАТАВРЕМЯ(1, 1, 1)) КАК ДатаПартии
	|ИЗ
	|	ОстаткиПоПартиям КАК ОстаткиПоПартиям
	|
	|УПОРЯДОЧИТЬ ПО
	|	Номенклатура,
	|	ДатаПартии,
	|	Характеристика,
	|	Серия";

	Запрос.УстановитьПараметр("Склад", Склад);
	Запрос.УстановитьПараметр("СписокНоменклатуры", СписокНоменклатуры);
	Запрос.УстановитьПараметр("ТоварыКСписанию", ТоварыКСписанию);

	РезультатыЗапроса = Запрос.ВыполнитьПакет();

	// Проверяем наличие недостатка остатков (результат 3)
	ВыборкаНедостаток = РезультатыЗапроса[3].Выбрать();
	Если ВыборкаНедостаток.Следующий() Тогда
		ТекстОшибки = "Недостаточно остатков для списания:" + Символы.ПС;
		Пока Истина Цикл
			ТекстОшибки = ТекстОшибки + СтрШаблон(
				"  %1: требуется %2, в наличии %3",
				ВыборкаНедостаток.Наименование,
				Формат(ВыборкаНедостаток.КоличествоТребуется, "ЧДЦ=3; ЧН=0"),
				Формат(ВыборкаНедостаток.ВсегоВНаличии, "ЧДЦ=3; ЧН=0")) + Символы.ПС;
			Если Не ВыборкаНедостаток.Следующий() Тогда
				Прервать;
			КонецЕсли;
		КонецЦикла;
		ВызватьИсключение ТекстОшибки;
	КонецЕсли;

	// Получаем остатки по партиям (результат 4)
	ТаблицаОстатков = РезультатыЗапроса[4].Выгрузить();

	// Индексируем для быстрого поиска
	ТаблицаОстатков.Индексы.Добавить("Номенклатура");

	// Распределяем по партиям методом FIFO
	Для Каждого СтрокаТовара Из ТоварыКСписанию Цикл

		ОсталосьСписать = СтрокаТовара.Количество;

		// Находим строки остатков для данной номенклатуры
		СтруктураОтбора = Новый Структура("Номенклатура", СтрокаТовара.Номенклатура);
		НайденныеСтроки = ТаблицаОстатков.НайтиСтроки(СтруктураОтбора);

		Для Каждого СтрокаОстатка Из НайденныеСтроки Цикл

			Если ОсталосьСписать <= 0 Тогда
				Прервать;
			КонецЕсли;

			Если СтрокаОстатка.ВНаличии <= 0 Тогда
				Продолжить;
			КонецЕсли;

			// Определяем количество к списанию из данной партии
			КоличествоИзПартии = Мин(ОсталосьСписать, СтрокаОстатка.ВНаличии);

			// Добавляем в результат
			НоваяСтрока = РезультатРаспределения.Добавить();
			НоваяСтрока.Номенклатура = СтрокаОстатка.Номенклатура;
			НоваяСтрока.Характеристика = СтрокаОстатка.Характеристика;
			НоваяСтрока.Серия = СтрокаОстатка.Серия;
			НоваяСтрока.Количество = КоличествоИзПартии;

			// Уменьшаем остаток в таблице и счетчик
			СтрокаОстатка.ВНаличии = СтрокаОстатка.ВНаличии - КоличествоИзПартии;
			ОсталосьСписать = ОсталосьСписать - КоличествоИзПартии;

		КонецЦикла;

	КонецЦикла;

	Возврат РезультатРаспределения;

КонецФункции
