		|	КурсыВалютСрезПоследних.Валюта КАК Валюта,
		|	КурсыВалютСрезПоследних.Курс КАК Курс,
		|	КурсыВалютСрезПоследних.Кратность КАК Кратность
		|ИЗ
		|	РегистрСведений.КурсыВалют.СрезПоследних(&ДатаКурса, Валюта В (&ИсходнаяВалюта, &НоваяВалюта)) КАК КурсыВалютСрезПоследних";

	Запрос.УстановитьПараметр("ДатаКурса", ДатаКурса);
	Запрос.УстановитьПараметр("ИсходнаяВалюта", ИсходнаяВалюта);
	Запрос.УстановитьПараметр("НоваяВалюта", НоваяВалюта);

	Результат = Запрос.Выполнить();
	Выборка = Результат.Выбрать();

	КурсИсходной = 0;
	КратностьИсходной = 0;
	КурсНовой = 0;
	КратностьНовой = 0;

	Пока Выборка.Следующий() Цикл
		Если Выборка.Валюта = ИсходнаяВалюта Тогда
			КурсИсходной = Выборка.Курс;
			КратностьИсходной = Выборка.Кратность;
		ИначеЕсли Выборка.Валюта = НоваяВалюта Тогда
			КурсНовой = Выборка.Курс;
			КратностьНовой = Выборка.Кратность;
		КонецЕсли;
	КонецЦикла;

	// Проверка наличия курсов
	Если КурсИсходной = 0 Или КратностьИсходной = 0 Тогда
		ВызватьИсключение СтрШаблон("Не найден курс валюты %1 на дату %2", ИсходнаяВалюта, Формат(ДатаКурса, "ДЛФ=D"));
