	КонецЕсли;

	// Расчёт кросс-курса: из исходной в новую
	// Кросс-курс = (КурсИсходной / КратностьИсходной) / (КурсНовой / КратностьНовой)
	КроссКурс = (КурсИсходной * КратностьНовой) / (КурсНовой * КратностьИсходной);

	// Пересчёт табличной части
	Для Каждого СтрокаТовары Из ТоварыТЧ Цикл
		СтрокаТовары.Цена = Окр(СтрокаТовары.Цена * КроссКурс, 2);
		СтрокаТовары.Сумма = Окр(СтрокаТовары.Цена * СтрокаТовары.Количество, 2);
	КонецЦикла;

