Процедура ПересчитатьСуммыПриСменеВалюты(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса) Экспорт

	Если ИсходнаяВалюта = НоваяВалюта Тогда
		Возврат;
	КонецЕсли;

	КурсИсходной = ПолучитьКурсВалюты(ИсходнаяВалюта, ДатаКурса);
	КурсНовой   = ПолучитьКурсВалюты(НоваяВалюта, ДатаКурса);

	Коэффициент = (КурсИсходной.Курс / КурсИсходной.Кратность) / (КурсНовой.Курс / КурсНовой.Кратность);

	Для Каждого СтрокаТовара Из Товары Цикл
		СтрокаТовара.Цена  = СтрокаТовара.Цена * Коэффициент;
		СтрокаТовара.Сумма = СтрокаТовара.Сумма * Коэффициент;
	КонецЦикла;

КонецПроцедуры

Функция ПолучитьКурсВалюты(Валюта, ДатаКурса)

	ТаблицаКурса = РегистрСведений.КурсыВалют.СрезПоследних(ДатаКурса, Валюта = Валюта);
	Если ТаблицаКурса.Количество() = 0 Тогда
		ВызватьИсключение "Отсутствует курс валюты на дату " + Формат(ДатаКурса, "ДФ=dd.MM.yyyy") + ": " + Валюта;
	КонецЕсли;

	Выборка = ТаблицаКурса.Выбрать();
	Выборка.Следующий();

	Результат = Новый Структура;
	Результат.Вставить("Курс", Выборка.Курс);
	Результат.Вставить("Кратность", Выборка.Кратность);

	Возврат Результат;

КонецФункции

Процедура ПересчитатьСуммыПриСменеВалюты(ТабличнаяЧастьТовары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса) Экспорт

	Если ИсходнаяВалюта = НоваяВалюта Тогда
		Возврат;
	КонецЕсли;

	Запрос = Новый Запрос;
	Запрос.Текст = 
		"ВЫБРАТЬ
		|	КурсыВалютСрезПоследних.Курс КАК Курс,
		|	КурсыВалютСрезПоследних.Кратность КАК Кратность
		|ИЗ
		|	РегистрСведений.КурсыВалют.СрезПоследних(&ДатаКурса, Валюта = &Валюта) КАК КурсыВалютСрезПоследних";

	Запрос.УстановитьПараметр("ДатаКурса", ДатаКурса);

	// Получаем курс исходной валюты
	Запрос.УстановитьПараметр("Валюта", ИсходнаяВалюта);
	ВыборкаИсходная = Запрос.Выполнить().Выбрать();
	Если НЕ ВыборкаИсходная.Следующий() Тогда
		ВызватьИсключение "Не задан курс для валюты: " + ИсходнаяВалюта;
	КонецЕсли;

	КурсИз = ВыборкаИсходная.Курс;
	КратностьИз = ВыборкаИсходная.Кратность;

	// Получаем курс новой валюты
	Запрос.SetParam("Валюта", НоваяВалюта);
	ВыборкаНовая = Запрос.Выполнить().Выбрать();
	Если НЕ ВыборкаНовая.Следующий() Тогда
		ВызватьИсключение "Не задан курс для валюты: " + НоваяВалюта;
	КонецЕсли;

	КурсВ = ВыборкаНовая.Курс;
	КратностьВ = ВыборкаНовая.Кратность;

	// Коэффициент пересчета (Кросс-курс)
	Коэффициент = (КурсИз / КратностьИз) / (КурсВ / КратностьВ);

	Для Каждого СтрокаТовар Из ТабличнаяЧастьТовары Цикл

		СтрокаТовар.Цена = Окр(СтрокаТовар.Цена * Коэффициент, 2);

		// Пересчет суммы с учетом возможной ручной скидки
		СтрокаТовар.Сумма = Окр(СтрокаТовар.Количество * СтрокаТовар.Цена, 2);

		Если ТабличнаяЧастьТовары.Колонки.Найти("СуммаНДС") <> Неопределено Тогда
			// В УТ11 расчет НДС обычно зависит от настроек налогообложения, 
			// здесь базовый пересчет пропорционально сумме
			СтрокаТовар.СуммаНДС = Окр(СтрокаТовар.СуммаНДС * Коэффициент, 2);
		КонецЕсли;

		Если ТабличнаяЧастьТовары.Колонки.Найти("СуммаСНДС") <> Неопределено Тогда
			СтрокаТовар.СуммаСНДС = СтрокаТовар.Сумма + ?(ТабличнаяЧастьТовары.Колонки.Найти("ЦенаВключаетНДС") <> Неопределено И СтрокаТовар.ЦенаВключаетНДС, 0, СтрокаТовар.СуммаНДС);
		КонецЕсли;

	КонецЦикла;

КонецПроцедуры
